        internal class UpgradeRecommendedCommandsToEase3And4 : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE3
                )
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE4
                )
            }

            private fun migrateBindings(
                preferences: SharedPreferences,
                oldPreferenceKey: String,
                targetCommand: ViewerCommand
            ) {
                if (!preferences.contains(oldPreferenceKey)) {
                    Timber.v("No preference to upgrade for: '%s'", oldPreferenceKey)
                    return
                }

                val oldBindingsString = preferences.getString(oldPreferenceKey, null)
                if (oldBindingsString.isNullOrEmpty()) {
                    Timber.v("Empty binding string for: '%s'", oldPreferenceKey)
                    preferences.edit { remove(oldPreferenceKey) }
                    return
                }

                Timber.i("Migrating bindings from '%s' to '%s'", oldPreferenceKey, targetCommand.preferenceKey)

                val oldBindings = MappableBinding.fromPreferenceString(oldPreferenceKey)
                for (binding in oldBindings) {
                    targetCommand.addBindingAtEnd(preferences, binding)
                }

                preferences.edit { remove(oldPreferenceKey) }
            }
        }
    }
